import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { PlusCircle, Store, ArrowLeft, Loader2, Navigation, MapPin, Trash2 } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

// Solución íconos Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const DashboardVendedor = () => {
  const { user } = useAuth();
  const [locales, setLocales] = useState([]);
  const [localActivo, setLocalActivo] = useState(null);
  const [mostrarFormLocal, setMostrarFormLocal] = useState(false);
  const [buscandoDireccion, setBuscandoDireccion] = useState(false);

  const [nuevoLocal, setNuevoLocal] = useState({
    nombre: '',
    direccion: '',
    lng: -65.2176,
    lat: -26.8161
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { if (user) fetchLocales(); }, [user]);

  const fetchLocales = async () => {
    try {
      const idVendedor = user.id || user._id;
      const res = await axios.get(`${API_URL}/api/locales/vendedor/${idVendedor}`);
      setLocales(res.data);
    } catch (err) { console.error("Error al traer locales", err); }
  };

  const fetchAddress = async (lat, lng) => {
    setBuscandoDireccion(true);
    try {
      const res = await axios.get(`${API_URL}/api/locales/reverse-geocode`, {
        params: { lat, lon: lng }
      });
      
      if (res.data && res.data.address) {
        const a = res.data.address;
        const calle = a.road || a.pedestrian || '';
        const nro = a.house_number || '';
        const ciudad = a.city || a.town || '';
        const dirFinal = `${calle} ${nro}${calle && nro ? ',' : ''} ${ciudad}`.trim();
        
        setNuevoLocal(prev => ({ 
          ...prev, 
          direccion: dirFinal || res.data.display_name.split(',')[0], 
          lat, lng 
        }));
      }
    } catch (error) {
      console.error("Error conexión backend", error);
      setNuevoLocal(prev => ({ ...prev, lat, lng }));
    } finally {
      setBuscandoDireccion(false);
    }
  };

  const LocationMarker = () => {
    useMapEvents({
      click(e) { fetchAddress(e.latlng.lat, e.latlng.lng); },
    });
    return <Marker position={[nuevoLocal.lat, nuevoLocal.lng]} />;
  };

  const handleCrearLocal = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/api/locales`, {
        ...nuevoLocal,
        vendedorId: user.id || user._id
      });
      fetchLocales();
      setMostrarFormLocal(false);
      setNuevoLocal({ nombre: '', direccion: '', lng: -65.2176, lat: -26.8161 });
    } catch (err) { alert("Error al guardar local"); }
  };

  const handleEliminar = async (id, e) => {
    e.stopPropagation();
    if(!window.confirm("¿Eliminar este local?")) return;
    try {
        await axios.delete(`${API_URL}/api/locales/${id}`);
        fetchLocales();
    } catch (err) { alert("Error al eliminar"); }
  };

  if (!localActivo) {
    return (
      <div style={containerStyle}>
        <div style={headerStyle}>
          <h2>Mis Locales</h2>
          <button onClick={() => setMostrarFormLocal(!mostrarFormLocal)} style={btnPrimary}>
            {mostrarFormLocal ? 'Volver' : <><PlusCircle size={18}/> Nuevo Local</>}
          </button>
        </div>

        {mostrarFormLocal ? (
          <div style={formCard}>
            <div style={formLayout}>
              <form onSubmit={handleCrearLocal} style={inputsContainer}>
                <h3 style={{margin:0}}>Configuración del Local</h3>
                <label style={labelL}>Nombre del Negocio</label>
                <input style={inputS} placeholder="Ej: Fiambrería 'Lo de Juan'" value={nuevoLocal.nombre} onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} required />
                
                <label style={labelL}>Dirección (Se completa al tocar el mapa)</label>
                <div style={{ position: 'relative' }}>
                  <input style={inputS} placeholder="Calle y Nro..." value={nuevoLocal.direccion} onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} required />
                  {buscandoDireccion && <Loader2 size={18} style={spinner} />}
                </div>

                <div style={coordsBadge}>
                  <Navigation size={14} /> {nuevoLocal.lat.toFixed(5)} , {nuevoLocal.lng.toFixed(5)}
                </div>

                <button type="submit" style={btnSubmit} disabled={buscandoDireccion}>Confirmar y Crear</button>
              </form>

              <div style={mapWrapper}>
                <p style={mapHint}>Toca el punto exacto en el mapa:</p>
                <MapContainer center={[nuevoLocal.lat, nuevoLocal.lng]} zoom={14} style={mapStyle}>
                  <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
                  <LocationMarker />
                </MapContainer>
              </div>
            </div>
          </div>
        ) : (
          <div style={gridLocales}>
            {locales.map(l => (
              <div key={l._id} style={cardLocal} onClick={() => setLocalActivo(l)}>
                <button style={btnDelete} onClick={(e) => handleEliminar(l._id, e)}><Trash2 size={16}/></button>
                <Store size={40} color="#e67e22" />
                <h3 style={{margin:'15px 0 5px 0'}}>{l.nombre}</h3>
                <p style={{fontSize:'0.85rem', color:'#64748b', margin:0}}>{l.direccion}</p>
              </div>
            ))}
            {locales.length === 0 && <div style={emptyBox}>Presiona 'Nuevo Local' para empezar.</div>}
          </div>
        )}
      </div>
    );
  }

  return (
    <div style={containerStyle}>
       <button onClick={() => setLocalActivo(null)} style={btnBack}><ArrowLeft size={18}/> Volver al listado</button>
       <div style={activeHeader}>
          <h1>{localActivo.nombre}</h1>
          <p>{localActivo.direccion}</p>
       </div>
       <div style={placeholderPanel}>
          Aquí puedes cargar ofertas y gestionar pedidos.
       </div>
    </div>
  );
};

